from __future__ import annotations

import base64
import zlib

from PySide6.QtGui import QIcon, QPixmap

_LOGO_ICO_DATA = """"""
_LOGO_PNG_DATA = """"""


def _decode_asset(encoded_text: str) -> bytes:
    return zlib.decompress(base64.b64decode(encoded_text.encode("ascii")))


def _load_pixmap(encoded_text: str, image_format: str) -> QPixmap:
    pixmap = QPixmap()
    pixmap.loadFromData(_decode_asset(encoded_text), image_format)
    return pixmap


def get_logo_icon() -> QIcon:
    return QIcon(_load_pixmap(_LOGO_ICO_DATA, "ICO"))


def get_logo_pixmap() -> QPixmap:
    return _load_pixmap(_LOGO_PNG_DATA, "PNG")
